# scripts/validate-prompt-schema.py
import yaml, json, jsonschema, pathlib, sys

SCHEMA = {
    "type": "object",
    "required": ["apiVersion", "kind", "metadata", "model", "system", "variables"],
    "properties": {
        "apiVersion": {"type": "string", "pattern": "^prompts/v[0-9]+$"},
        "kind": {"const": "PromptTemplate"},
        "metadata": {
            "type": "object",
            "required": ["id", "version", "owner", "changelog"],
            "properties": {
                "version": {"type": "string", "pattern": r"^\d+\.\d+\.\d+$"},
                "owner": {"type": "string"},
                "changelog": {"type": "string", "minLength": 10},
            },
        },
        "model": {
            "type": "object",
            "required": ["id", "maxTokens"],
            "properties": {
                "id": {"type": "string"},
                "maxTokens": {"type": "integer", "minimum": 1, "maximum": 16384},
            },
        },
        "system": {"type": "string", "minLength": 20},
        "variables": {"type": "array"},
        "evals": {
            "type": "object",
            "required": ["suite", "minPassRate"],
            "properties": {
                "minPassRate": {"type": "number", "minimum": 0.0, "maximum": 1.0},
            },
        },
    },
}

errors = []
for path in pathlib.Path("prompts").rglob("*.yaml"):
    with open(path) as f:
        template = yaml.safe_load(f)
    try:
        jsonschema.validate(template, SCHEMA)
    except jsonschema.ValidationError as e:
        errors.append(f"{path}: {e.message}")

if errors:
    for err in errors:
        print(f"FAIL: {err}", file=sys.stderr)
    sys.exit(1)

print(f"All {sum(1 for _ in pathlib.Path('prompts').rglob('*.yaml'))} templates valid.")
